import React, { useState, useRef, useEffect } from 'react';
import { Inbox, Send, Trash2, Edit, Search, Star, X, Paperclip } from 'lucide-react';
import './css/Messaging.css';
import axios from '../axios'; // Make sure you have this import

const Messaging = ({ userId }) => {
    const [activeCategory, setActiveCategory] = useState('inbox');
    const [messages, setMessages] = useState([]);
    const [selectedMessage, setSelectedMessage] = useState(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [showNewMessageModal, setShowNewMessageModal] = useState(false);
    const [newMessage, setNewMessage] = useState({ to: '', subject: '', content: '', attachment: null });
    const fileInputRef = useRef(null);
    const [currentPage, setCurrentPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);

    useEffect(() => {
        fetchMessages(activeCategory, 1);
    }, [activeCategory]);

    const fetchMessages = async (category, page = 1) => {
        try {
            const response = await axios.get(`/api/messages/${category}?page=${page}`);
            setMessages(response.data.messages);
            setCurrentPage(response.data.currentPage);
            setTotalPages(response.data.totalPages);
        } catch (error) {
            console.error(`Error fetching ${category} messages:`, error);
            // You might want to show an error message to the user here
        }
    };

    const filteredMessages = messages.filter(message => 
        message.sender.username.toLowerCase().includes(searchTerm.toLowerCase()) ||
        message.subject.toLowerCase().includes(searchTerm.toLowerCase()) ||
        message.content.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const renderMessageList = () => {
        return filteredMessages.map(message => (
            <div 
                key={message._id} 
                className={`message-item ${!message.read ? 'unread' : ''} ${message.starred ? 'starred' : ''} ${selectedMessage && selectedMessage._id === message._id ? 'selected' : ''}`}
                onClick={() => setSelectedMessage(message)}
            >
                <div className="message-item-content">
                    <div className="message-header">
                        <span className="message-from">{activeCategory === 'sent' ? `To: ${message.recipient.username}` : `From: ${message.sender.username}`}</span>
                        <span className="message-date">{new Date(message.createdAt).toLocaleDateString()}</span>
                    </div>
                    <div className="message-subject">{message.subject}</div>
                    <div className="message-preview">{message.content}</div>
                </div>
                <button className="star-btn" onClick={(e) => {
                    e.stopPropagation();
                    toggleStarMessage(message._id);
                }}>
                    <Star size={16} className={message.starred ? 'starred' : ''} />
                </button>
            </div>
        ));
    };

    const toggleStarMessage = async (messageId) => {
        try {
            const response = await axios.patch(`/api/messages/${messageId}/star`);
            setMessages(prevMessages =>
                prevMessages.map(msg =>
                    msg._id === messageId ? { ...msg, starred: response.data.starred } : msg
                )
            );
        } catch (error) {
            console.error('Error starring message:', error);
            alert('Failed to star message. Please try again.');
        }
    };

    const renderMessageDetail = () => {
        if (!selectedMessage) return null;
        return (
            <div className="message-detail">
                <h3>{selectedMessage.subject}</h3>
                <div className="message-info">
                    <span>From: {selectedMessage.sender.username}</span>
                    <span>Date: {new Date(selectedMessage.createdAt).toLocaleDateString()}</span>
                </div>
                <div className="message-content">{selectedMessage.content}</div>
                <button className="reply-btn" onClick={() => {/* Implement reply functionality */}}>
                    Reply
                </button>
                <button className="trash-btn" onClick={() => moveToTrash(selectedMessage._id)}>
                    Move to Trash
                </button>
            </div>
        );
    };

    const handleNewMessage = () => {
        setShowNewMessageModal(true);
    };

    const closeNewMessageModal = () => {
        setShowNewMessageModal(false);
        setNewMessage({ to: '', subject: '', content: '', attachment: null });
    };

    const handleNewMessageChange = (e) => {
        const { name, value } = e.target;
        setNewMessage(prev => ({ ...prev, [name]: value }));
    };

    const handleFileChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            setNewMessage(prev => ({ ...prev, attachment: file }));
        }
    };

    const triggerFileInput = () => {
        fileInputRef.current.click();
    };

    const sendNewMessage = async () => {
        try {
            const response = await axios.post('/api/messages', {
                recipient: newMessage.to, // Assuming 'to' contains the recipient's user ID
                subject: newMessage.subject,
                content: newMessage.content
            });

            // If the message was sent successfully, add it to the messages array
            const sentMessage = response.data.data;
            setMessages(prevMessages => [
                {
                    id: sentMessage._id,
                    from: 'You',
                    to: newMessage.to,
                    subject: sentMessage.subject,
                    content: sentMessage.content,
                    date: new Date(sentMessage.createdAt).toISOString().split('T')[0],
                    read: true,
                    starred: false
                },
                ...prevMessages
            ]);

            // Close the modal and reset the new message form
            closeNewMessageModal();
        } catch (error) {
            console.error('Error sending message:', error);
            // Here you might want to show an error message to the user
            alert('Failed to send message. Please try again.');
        }
    };

    const renderNewMessageModal = () => {
        if (!showNewMessageModal) return null;
        return (
            <div className="new-message-modal">
                <div className="new-message-content">
                    <div className="new-message-header">
                        <h3>New Message</h3>
                        <button onClick={closeNewMessageModal} className="close-btn">
                            <X size={18} />
                        </button>
                    </div>
                    <div className="new-message-form">
                        <input
                            type="text"
                            name="to"
                            placeholder="Recipient User ID"
                            value={newMessage.to}
                            onChange={handleNewMessageChange}
                        />
                        <input
                            type="text"
                            name="subject"
                            placeholder="Subject"
                            value={newMessage.subject}
                            onChange={handleNewMessageChange}
                        />
                        <textarea
                            name="content"
                            placeholder="Message"
                            value={newMessage.content}
                            onChange={handleNewMessageChange}
                        />
                        <div className="attachment-section">
                            <button onClick={triggerFileInput} className="attachment-btn">
                                <Paperclip size={18} />
                                Attach File
                            </button>
                            <input
                                type="file"
                                ref={fileInputRef}
                                onChange={handleFileChange}
                                style={{ display: 'none' }}
                            />
                            {newMessage.attachment && (
                                <span className="attachment-name">{newMessage.attachment.name}</span>
                            )}
                        </div>
                        <button onClick={sendNewMessage} className="send-btn">Send</button>
                    </div>
                </div>
            </div>
        );
    };

    const moveToTrash = async (messageId) => {
        try {
            await axios.patch(`/api/messages/${messageId}/trash`);
            setMessages(prevMessages => prevMessages.filter(msg => msg._id !== messageId));
            if (selectedMessage && selectedMessage._id === messageId) {
                setSelectedMessage(null);
            }
        } catch (error) {
            console.error('Error moving message to trash:', error);
            alert('Failed to move message to trash. Please try again.');
        }
    };

    const handlePageChange = (newPage) => {
        if (newPage >= 1 && newPage <= totalPages) {
            fetchMessages(activeCategory, newPage);
        }
    };

    return (
        <div className="messaging-container">
            <div className="messaging-sidebar">
                <button className="new-message-btn" onClick={handleNewMessage}>
                    <Edit size={18} />
                    New Message
                </button>
                <div className="message-categories">
                    <button
                        className={`category-btn ${activeCategory === 'inbox' ? 'active' : ''}`}
                        onClick={() => setActiveCategory('inbox')}
                    >
                        <Inbox size={18} />
                        Inbox
                    </button>
                    <button
                        className={`category-btn ${activeCategory === 'sent' ? 'active' : ''}`}
                        onClick={() => setActiveCategory('sent')}
                    >
                        <Send size={18} />
                        Sent
                    </button>
                    <button
                        className={`category-btn ${activeCategory === 'trash' ? 'active' : ''}`}
                        onClick={() => setActiveCategory('trash')}
                    >
                        <Trash2 size={18} />
                        Trash
                    </button>
                </div>
            </div>
            <div className="messaging-content">
                <div className="messaging-header">
                    <h2>{activeCategory.charAt(0).toUpperCase() + activeCategory.slice(1)}</h2>
                    <div className="search-bar">
                        <input 
                            type="text" 
                            placeholder="Search messages..." 
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                        <Search size={18} />
                    </div>
                </div>
                <div className="message-list-container">
                    <div className="message-list">
                        {renderMessageList()}
                    </div>
                    <div className="pagination">
                        <button onClick={() => handlePageChange(currentPage - 1)} disabled={currentPage === 1}>
                            Previous
                        </button>
                        <span>{currentPage} / {totalPages}</span>
                        <button onClick={() => handlePageChange(currentPage + 1)} disabled={currentPage === totalPages}>
                            Next
                        </button>
                    </div>
                    <div className="message-detail-container">
                        {renderMessageDetail()}
                    </div>
                </div>
            </div>
            {renderNewMessageModal()}
        </div>
    );
};

export default Messaging;
